"""
MKT Christ Commentary — Psalms chapters 86–89
Run: python3 scripts/zc-christ-psalms-86-89.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/mkt-christ/psalms.json (continuity)

Key Christological decisions in this range:
- Ps 86:5 — "forgiving, abounding in steadfast love" = Exod 34:6 divine-name formula;
  Christ embodies this name (John 1:14 "grace and truth"). Luke 23:34 ("Father, forgive them")
  is the enacted form of v5.
- Ps 86:9 — "all nations will bow before you" = Phil 2:10-11 (every knee shall bow);
  the universal eschatological worship directed to the God of Israel now specifically fulfilled
  in the worship of the risen Christ.
- Ps 86:13 — "rescued from the lowest depths of Sheol" = Acts 2:24/Heb 13:20; treated as
  direct anticipation of the resurrection.
- Ps 87:4-6 — Gentiles "born in Zion" = the new covenant community (Gal 4:26; Rev 21); the
  divine enrollment of peoples = Luke 10:20 / Rev 21:27 (Lamb's book of life).
- Ps 88 — the darkest psalm, no resolution; treated as the shadow of the dereliction and
  entombment; v9 "spread out my hands" = a crucifixion posture; vv10-12 = the questions the
  resurrection answers; v14 = the nadir of passion (parallel Ps 22:1 / Matt 27:46).
- Ps 89 — the Davidic covenant psalm (2 Sam 7 in song form) followed by apparent collapse.
  The "if" clauses of vv30-32 explain why all human Davidic kings failed; Christ alone is the
  Davidic heir who keeps covenant perfectly. v27 ("firstborn, highest of the kings of the earth")
  is directly cited in Rev 1:5 — the strongest direct citation of this range. vv38-51 describe
  the passion as apparent divine abandonment of the covenant; v52 is the doxology that closes
  Book III and points to the resurrection as the answer.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ for Psalms 86-89 — David's prayer of humble dependence (Ps 86), the
#   Zion-census vision of Gentile inclusion (Ps 87), the unresolved dark-night lament (Ps 88),
#   and the great Davidic covenant psalm that ends in apparent collapse (Ps 89). Together
#   these form the theological heart of Book III: the suffering of the anointed king, the
#   international scope of YHWH's purpose, and the crisis that only the resurrection resolves.
# CHANGE? If commentary/mkt-christ/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/psalms.json'));
#   [print(ch, len(d.get(ch,{}))) for ch in ['86','87','88','89']]"

PSALMS = {
  "86": {
    "1": "<p>A Prayer of David — \"Turn your ear toward me, O LORD, and answer me, for I am poor and needy.\" Hebrews 5:7 describes Christ's prayer life in almost precisely these terms: \"During the days of Jesus's life on earth, he offered up prayers and petitions with fervent crying and tears to the one who could save him from death, and he was heard because of his reverent submission.\" The posture of poverty and need before God — the kenosis of the one who \"did not consider equality with God something to be grasped\" (Phil 2:6) — is modeled by Christ throughout his earthly life and explicitly in Gethsemane (Matt 26:36-46).</p>",
    "2": "<p>\"Preserve my soul, for I am devoted to you; save your servant who trusts in you.\" The servant-language (<em>avdekha</em>, your servant) applied by David to himself points forward to the Servant of Isaiah 40-55, which the NT applies to Christ. Isaiah 42:1 (\"here is my servant, whom I uphold\") is cited in Matt 12:18 as fulfilled in Jesus. The trust of the servant who depends entirely on YHWH for soul-preservation is the faith that Hebrews 12:2 attributes to Jesus: \"for the joy set before him he endured the cross, scorning its shame,\" trusting in the vindication that followed.</p>",
    "3": "<p>\"Be gracious to me, O Lord, for I cry out to you all day long.\" The petition for grace and the persistence of the cry — \"all day long\" — are the marks of continuous prayer. Luke 18:1 (\"always pray and not give up\") and 1 Thess 5:17 (\"pray continually\") are grounded in Christ's own practice of sustained prayer. Luke records that Jesus often withdrew to pray (Luke 5:16; 6:12) and that on the night before the crucifixion he \"prayed more earnestly\" until his sweat fell like blood (Luke 22:44). The all-day cry is the prayer posture Christ both modeled and commands.</p>",
    "4": "<p>\"Gladden the soul of your servant, for to you, O Lord, I lift up my soul.\" The upward lifting of the soul to YHWH as the source of joy anticipates John 17:13 (Christ's prayer: \"I say these things while I am still in the world, so that they may have the full measure of my joy within them\") and Heb 12:2 (\"for the joy set before him he endured the cross\"). The servant's soul gladdened by God alone is the pattern of Christ who \"rejoiced in the Holy Spirit\" (Luke 10:21) precisely in the context of the disciples' mission.</p>",
    "5": "<p>\"For you, O Lord, are good and forgiving, abounding in steadfast love for all who call on you.\" A direct echo of the Exodus 34:6-7 divine name-formula (\"compassionate and gracious... abounding in steadfast love\"). In Christ, this name takes flesh: John 1:14 (\"full of grace and truth\") is John's equivalent of the Exodus formula applied to the incarnate Word. Luke 23:34 (\"Father, forgive them, for they do not know what they are doing\") is the enacted form of the \"forgiving\" character of v5 — Christ on the cross embodies the forgiveness and hesed that the divine name proclaims.</p>",
    "6": "<p>\"Give ear to my prayer, O LORD; listen to the voice of my plea for mercy.\" The cry for a listening ear is the foundational posture of dependence that Christ models. Hebrews 5:7 (\"he was heard because of his reverent submission\") confirms that the Father's ear was open to the Son's cries. Psalm 22:24 makes the same claim retrospectively: \"he did not despise or scorn the suffering of the afflicted one; he did not hide his face from him but listened to his cry for help.\" The hearing of Christ's prayers is the guarantee that Christ-united believers will also be heard (1 John 5:14-15).</p>",
    "7": "<p>\"On the day of my trouble I call to you, for you answer me.\" The confidence of being heard — \"you answer me\" — is the trust-claim that Jesus embodies. John 11:41-42 (\"Father, I thank you that you have heard me; I knew that you always hear me\") shows Christ's certainty of the Father's responsiveness as the basis of his prayer. The resurrection is the ultimate answer to the \"day of trouble\" of the crucifixion — the Father's response to Christ's prayer arrives not as escape from death but as victory over it.</p>",
    "8": "<p>\"There is no one like you among the gods, O Lord, and no works compare to yours.\" The incomparability of YHWH — the <em>mi-kamokha</em> tradition of Exod 15:11 — is the theological ground on which Christ's unique identity is established. Philippians 2:9-11 (\"God exalted him to the highest place and gave him the name that is above every name\") gives the name above all names to Jesus. 1 Cor 8:6 identifies Christ as the Lord through whom all things exist. The incomparable God reveals himself to be Father, Son, and Spirit — the \"no one like you\" applies to the triune God revealed in Christ.</p>",
    "9": "<p>\"All the nations you have made will come and bow before you, O Lord, and they will glorify your name.\" A direct citation-pattern: Philippians 2:10-11 (\"every knee shall bow... and every tongue acknowledge that Jesus Christ is Lord\") combines this verse with Isaiah 45:23. The nations who will bow before YHWH and glorify his name are, in the NT's reading, those who bow before the risen Christ — because the risen Christ is the form in which YHWH's name and honor are made known among all nations. Revelation 15:4 (\"All nations will come and worship before you\") is the eschatological fulfillment.</p>",
    "10": "<p>\"For you are great and you do wonders; you alone are God.\" The exclusivity — \"you alone are God\" — is the monotheistic affirmation that the NT reframes in a Trinitarian direction without compromising. John 10:30 (\"I and the Father are one\") and John 1:1 (\"the Word was God\") place Christ within the divine identity. The \"wonders\" that YHWH alone does are what Acts 2:22 attributes to Jesus: \"a man accredited by God to you by miracles, wonders and signs.\" The \"God alone\" who does wonders does them through the Son.</p>",
    "11": "<p>\"Teach me your way, O LORD, that I may walk in your truth; give me an undivided heart to reverence your name.\" The \"undivided heart\" is the singleness of devotion that characterizes Christ's relationship to the Father. John 8:29 (\"I always do what pleases him\") and John 17:4 (\"I have brought you glory on earth by finishing the work you gave me to do\") describe an undivided, whole-heart consecration. Hebrews 7:26 (\"such a high priest truly meets our need — one who is holy, blameless, pure\") is the doctrinal form. The Spirit works this same undivided heart in believers (Ezek 36:26; Heb 10:22).</p>",
    "12": "<p>\"I will thank you, O Lord my God, with my whole heart; I will glorify your name forever.\" The whole-heart thanksgiving and eternal glorification of the divine name are the liturgical posture of the Son who glorifies the Father. John 17:1 (\"Father, the hour has come. Glorify your Son, that your Son may glorify you\") — the glorification is mutual and eternal. Hebrews 13:15 (\"continually offer to God a sacrifice of praise — the fruit of lips that openly profess his name\") gives the community form of whole-heart thanksgiving, enabled by Christ as the new covenant high priest.</p>",
    "13": "<p>\"For your steadfast love toward me is great; you have rescued my soul from the lowest depths of Sheol.\" A direct anticipation of the resurrection. \"Rescued from the lowest depths of Sheol\" is the language Acts 2:24 applies to the resurrection: \"God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him.\" Hebrews 13:20 (\"the God of peace, who through the blood of the eternal covenant brought back from the dead our Lord Jesus\") is the doxological form of this rescue. The great hesed that motivates the rescue is the covenant love that sends the Son into death and raises him from it.</p>",
    "14": "<p>\"O God, arrogant men have risen up against me; a band of ruthless men seeks my life — they do not keep you before them.\" The portrait of enemies who seek the life of the anointed one without keeping God before them is the pattern fulfilled in the passion narrative. Mark 14:1 (\"the chief priests and teachers of the law were looking for some way to arrest Jesus secretly and kill him\") and John 11:53 (\"from that day on they plotted to take his life\") describe the ruthless men seeking the life of the one God anointed. \"They do not keep you before them\" is the practical atheism of those who treat Jesus as a problem to be solved rather than the Son of God.</p>",
    "15": "<p>\"But you, O Lord, are a compassionate and gracious God, slow to anger, abounding in steadfast love and faithfulness.\" The Exodus 34:6-7 formula again — the pivot from enemy-threat (v14) to divine character (v15) is the pattern of confident faith. John 1:14 (\"full of grace and truth\") translates this formula into the incarnate Word. James 5:11 (\"the Lord is full of compassion and mercy\") cites this character of God as the ground of perseverance under suffering. Christ's compassion for the crowd (Matt 9:36), his slowness to anger toward the disciples, and his abundant steadfast love enacted in the cross all embody this verse's portrait of divine character.</p>",
    "16": "<p>\"Turn to me and be gracious to me; give your strength to your servant, and save the son of your maidservant.\" The phrase \"son of your maidservant\" — a servant born in the household, with the deepest covenant ties to the master — describes the intimacy of the servant relationship. Isaiah 49:5 uses similar servant-birth language of the Servant who is formed from the womb to bring Jacob back to God. The giving of divine strength to the servant is what Luke 4:14 describes: Jesus returned from the wilderness \"in the power of the Spirit.\" The prayer for strength is answered in the Spirit's empowering presence.</p>",
    "17": "<p>\"Show me a sign of your favor, so that those who hate me will see and be ashamed, because you, O LORD, have helped me and comforted me.\" The sign of divine favor that vindicates the righteous against those who hate them is the resurrection. Matthew 12:39-40 (\"no sign will be given... except the sign of the prophet Jonah\") — the resurrection is the only sign given. Acts 2:32-36 presents the resurrection as the vindication proving that those who rejected Christ crucified \"both Lord and Messiah.\" The shame of the haters is not gloated over but is the inverse of the vindication: the resurrection proves the Father's help and comfort, defeating the enmity's claims.</p>"
  },
  "87": {
    "1": "<p>\"His foundation is on the holy mountains.\" The Zion psalm opens by grounding the city of God in the divine choice of the holy mountains as foundation. Hebrews 12:22 (\"you have come to Mount Zion, to the city of the living God, the heavenly Jerusalem\") is the NT's reinterpretation: believers in Christ have \"come to\" the true Zion that Psalm 87 describes — not by geography but by covenant. The foundation of the city in the holy mountains is the security that Christ provides for his church: Matthew 16:18 (\"on this rock I will build my church, and the gates of death will not overcome it\").</p>",
    "2": "<p>\"The LORD loves the gates of Zion more than all the dwelling places of Jacob.\" The divine preference for Zion over all other Israelite dwelling places is the OT form of the NT claim that Christ is the singular locus of divine presence. John 2:19-21 (\"destroy this temple and I will raise it again in three days\" — speaking of his body) transfers the temple/Zion presence-locus to Christ himself. Ephesians 2:20-22 (believers \"built on the foundation of the apostles and prophets, with Christ Jesus himself as the chief cornerstone... a holy temple in the Lord\") is the community form of this Zion-love.</p>",
    "3": "<p>\"Glorious things are spoken of you, O city of God.\" The glorious things spoken of Zion are the eschatological promises of restoration, Gentile inclusion, and divine dwelling. Revelation 21:9-27 devotes sustained attention to the \"glorious things\" of the new Jerusalem — its radiance, its gates, its nations, its Lamb-light. The connection between Ps 87 and Rev 21 is direct: both describe an international city whose population comes from the nations, whose foundation is divine, and whose glory surpasses anything human. Christ is the Lamb at the center of that city (Rev 21:23; 22:1).</p>",
    "4": "<p>\"Among those who acknowledge me I will name Rahab and Babylon; and behold — Philistia, Tyre, and Ethiopia: 'This one was born there.'\" The extraordinary claim: Israel's historic enemies (Rahab = Egypt; Babylon; Philistia; Tyre; Cush/Ethiopia) are enrolled in the divine register as born in Zion — citizens of the city of God. This is the OT anticipation of the Gentile inclusion that Paul elaborates in Romans 9-11 and Ephesians 2-3. Galatians 4:26 (\"the Jerusalem that is above is free, and she is our mother\") and Acts 2:5-11 (the nations gathered at Pentecost) are the NT fulfillments. In Christ, all nations find their true birthplace.</p>",
    "5": "<p>\"Of Zion it will be said, 'This one and that one were born in her,' and the Most High himself will establish her.\" The divine establishing of Zion — not through human means but by the Most High himself — is the pattern of the church's founding. Matthew 16:18 (\"I will build my church\") is Christ's claim to be the one who establishes the true Zion-community. The \"this one and that one\" born in her — individuals from across the nations registered as Zion-born — is the phenomenon of Pentecost (Acts 2:41: \"about three thousand were added\") and the ongoing growth of the church from every tribe and tongue (Rev 7:9).</p>",
    "6": "<p>\"When the LORD records the enrollment of the peoples, he will write, 'This one was born there.'\" The divine enrollment of peoples in the Zion-register is the OT form of the NT's \"book of life.\" Luke 10:20 (Christ to the disciples: \"rejoice that your names are written in heaven\") and Revelation 21:27 (\"only those whose names are written in the Lamb's book of life\" will enter the new Jerusalem) are the fulfillments. The enrollment is now specifically in the book of the Lamb — the crucified and risen Christ whose death is the basis for the registration. Being born in Zion means being born again through him (John 3:3-5).</p>",
    "7": "<p>\"Singers and dancers alike say, 'All my springs of life are in you.'\" The closing image of the psalm: the community of worship, with singers and dancers, declaring that all their living-springs are in Zion. John 4:14 (\"whoever drinks the water I give them will never thirst; indeed, the water I give them will become in them a spring of water welling up to eternal life\") and John 7:37-38 (\"rivers of living water will flow from within them\") are the specific NT fulfillments. Christ is the living spring that Psalm 87 locates in Zion; in him, the city of God becomes available to all who drink. Revelation 22:1 (the river of the water of life flowing from the throne of God and the Lamb) is the eschatological form.</p>"
  },
  "88": {
    "1": "<p>A psalm of Heman the Ezrahite — the darkest psalm in the Psalter. The superscription signals what the psalm delivers: unrelieved suffering with no praise-turn at the end. Psalm 88 is unique in ending in darkness. As such it is the closest OT analogue to the experience of Holy Saturday — the day between crucifixion and resurrection when the disciples' faith was extinguished and hope appeared dead. \"O LORD, my God, I cry to you for help; by day I cry out, at night before you\" — the unceasing cry of the one who prays but does not see the answer within the psalm's frame. Matthew 27:46 (\"My God, my God, why have you forsaken me?\") is the NT moment that Psalm 88 shadows.</p>",
    "2": "<p>\"Let my prayer come before you; turn your ear toward my cry.\" The prayer that seeks to break through — to \"come before\" YHWH — is the desperate persistence of the one whose situation seems to make prayer pointless. Christ in Gethsemane (Matt 26:36-46) prays three times when no answer comes in the form the prayer requests; still the prayer persists. Hebrews 5:7 (Christ's prayers \"to him who was able to save him from death\") shows that the Father did hear — but the hearing was resurrection, not escape from death. The ear that seems turned away will be shown, in the morning, to have been attentive all along.</p>",
    "3": "<p>\"For my soul is saturated with troubles, and my life draws near to Sheol.\" Matthew 26:38 (Christ in Gethsemane: \"my soul is overwhelmed with sorrow to the point of death\") — the verbal parallel is striking: the psalmist's soul \"saturated\" with troubles, Christ's soul \"overwhelmed\" with sorrow both to the point of death. John 12:27 (\"now my soul is troubled\") uses the same nearness-to-death language before the passion. These are not poetic hyperboles but descriptions of the actual weight of suffering — in Christ's case, the weight of the world's sin producing the Gethsemane agony.</p>",
    "4": "<p>\"I am reckoned among those who go down to the pit; I have become like a man with no strength at all.\" Isaiah 53:3 (\"a man of sorrows, familiar with pain\") and Isaiah 53:12 (\"he was numbered with the transgressors\") are the Servant parallel. Christ was literally \"reckoned among\" those who go down — he was buried, placed in the tomb among the dead. \"No strength at all\" is the kenosis enacted: Philippians 2:7-8 (\"he made himself nothing... becoming obedient to death — even death on a cross\"). The one with no remaining strength in himself is the one who will be raised by the Father's power (Rom 6:4).</p>",
    "5": "<p>\"Like one cast loose among the dead — like the slain who lie in the grave — those you no longer remember, cut off from your hand.\" The entombment language of Holy Saturday: cast loose among the dead, lying in the grave, apparently cut off from YHWH's hand. Acts 2:27 (citing Ps 16:10: \"you will not abandon me to the realm of the dead\") is the explicit contradiction of this verse's despair — the Father did not abandon Christ to Sheol even though Christ descended there. The cut-off-from-your-hand fear of Psalm 88:5 is answered by the resurrection's demonstration that Christ was never ultimately cut off (John 10:28-29).</p>",
    "6": "<p>\"You have placed me in the lowest pit, in utter darkness, in the depths below.\" The lowest pit and utter darkness are the nadir of the suffering. Philippians 2:8 (\"he humbled himself by becoming obedient to death — even death on a cross\") is the NT statement of the same descent to the lowest point. 1 Peter 3:19 (\"he went and made proclamation to the imprisoned spirits\") and Ephesians 4:9 (\"he also descended to the lower, earthly regions\") point to Christ's entry into this lowest pit as the precondition for his ascent \"far above all the heavens\" (Eph 4:10). Descent precedes ascent; the lowest pit is the launching point of the exaltation.</p>",
    "7": "<p>\"Your wrath presses down hard on me, and you have battered me with all your waves.\" The divine wrath that presses down — not an enemy's wrath but YHWH's own — is the theological element that distinguishes Christ's suffering from ordinary martyrdom. Isaiah 53:10 (\"yet it was the LORD's will to crush him and cause him to suffer\") makes the same point: the Father's purposive will is active in the crushing of the Servant. 2 Corinthians 5:21 (\"God made him who had no sin to be sin for us\") is the NT statement of why the wrath presses down on the sinless one: he bears what we deserved. The waves that batter are the waves of divine judgment against sin, absorbed by the one who had no sin.</p>",
    "8": "<p>\"You have pushed my companions far away from me; you have made me repulsive to them. I am sealed in and cannot get out.\" The abandonment by companions is the passion-pattern. Luke 23:49 (\"all those who knew him... stood at a distance, watching\") and Mark 14:50 (\"everyone deserted him and fled\") are the historical fulfillments. The sealing in is the entombment: Matthew 27:66 (the tomb sealed and guarded) makes the sealing literal. The companions pushed away because he was made \"repulsive\" — the crowd's rejection, the disciples' flight, and Peter's denial (Matt 26:69-75) are the social dimensions of the isolation. Christ is alone in the sealed tomb.</p>",
    "9": "<p>\"My eye wastes away with grief; O LORD, I call to you every day; I spread out my hands toward you.\" \"I spread out my hands toward you\" — the posture of crucifixion. The arms extended in prayer become the arms extended on the cross. Isaiah 65:2 (\"all day long I have held out my hands to an obstinate people\") describes YHWH spreading out his hands; here the righteous sufferer spreads out hands toward God. The daily calling despite wasting eyes — the persistent prayer in the face of apparent non-answer — is the pattern of Christ who prays in Gethsemane, who cries from the cross (Matt 27:46), and whose persistent trust is vindicated by resurrection.</p>",
    "10": "<p>\"Do you perform wonders for the dead? Can the departed arise and praise you?\" The psalm's despairing question contains the seed of the answer the resurrection gives. The question expects \"no\" within the psalm's frame. But the resurrection of Christ makes the answer permanently \"yes\" — God does perform wonders for the dead; the departed can arise and praise him. 1 Corinthians 15:17-20 (\"if Christ has not been raised... those who have fallen asleep in Christ are lost... but Christ has indeed been raised from the dead, the firstfruits of those who have fallen asleep\") is the direct answer to Psalm 88:10's despairing question.</p>",
    "11": "<p>\"Is your steadfast love announced in the grave? Is your faithfulness spoken of in Abaddon?\" The second despairing question — hesed and faithfulness silent in Sheol and Abaddon. Again, the resurrection answers what the psalmist could not see. Acts 13:32-34 (God's promise to David fulfilled in the resurrection) and Revelation 14:13 (\"blessed are the dead who die in the Lord\") show the dead within the sphere of divine hesed. Christ's announcement in the realm of the dead (1 Pet 3:19) is the specific entry of the hesed and faithfulness into the domain where the psalmist thought them absent.</p>",
    "12": "<p>\"Will your wonders be known in the darkness? Will your righteousness be heard of in the land of forgetting?\" The land of forgetting — Sheol as the place where the dead forget and are forgotten — is overcome by the resurrection. Christ's resurrection from the \"land of forgetting\" is the definitive answer: God's righteousness is made known precisely in the darkness and in the very place that was supposed to be beyond divine reach. Romans 3:25-26 (\"God presented Christ as a sacrifice of atonement... to demonstrate his justice\") is the declaration of divine righteousness in the place where the psalmist thought it silenced.</p>",
    "13": "<p>\"But I, O LORD, cry out to you; in the morning my prayer comes before you.\" The \"morning\" and the persistent prayer-approach — the morning is the time of resurrection. Luke 24:1 (\"very early in the morning, they came to the tomb\") and John 20:1 (\"early on the first day of the week, while it was still dark\") place the resurrection at the morning to which Psalm 88 has been praying through the darkness. The psalmist cries out and the morning comes; in Christ, the morning that comes is the resurrection morning that answers all the laments of the psalm. The \"but I\" of v13 — the persistence of prayer despite v12's apparent impossibility — is the faith that Easter vindicates.</p>",
    "14": "<p>\"O LORD, why do you reject my soul? Why do you hide your face from me?\" The nadir — the direct accusation of divine rejection and face-hiding. This parallels Psalm 22:1 (\"my God, my God, why have you forsaken me?\") and is the same dereliction cry that Christ makes from the cross (Matt 27:46). The hiding of the divine face is the experience of the wrath-bearing from the human side: the one who bears divine judgment against sin experiences the withdrawal of divine presence that sin produces. Christ enters this experience fully — not because of his own sin but because he bears the sin of the world (2 Cor 5:21). This is the experiential center of the atonement.</p>",
    "15": "<p>\"I have been afflicted and near death since my youth; I suffer your terrors; I am overcome.\" The sustained affliction \"since my youth\" — a lifetime of suffering rather than a temporary crisis — describes the pattern of the suffering Messiah. Isaiah 53:3 (\"familiar with pain\") and Hebrews 5:8 (\"although he was a son, he learned obedience from what he suffered\") describe Christ's progressive formation through suffering. The terrors — the overwhelming experiences of divine judgment and human hostility — are overcome throughout the passion narrative culminating in the cross, where the accumulated weight of all human sin and all divine judgment converges.</p>",
    "16": "<p>\"Your fierce wrath has swept over me; your terrors have destroyed me.\" The sweeping wrath and destroying terrors describe what Christ bore at the cross from the perspective of the sin-bearer. Isaiah 53:5 (\"the punishment that brought us peace was on him\") and Galatians 3:13 (\"Christ redeemed us from the curse of the law by becoming a curse for us\") give the NT interpretation: the fierce wrath that swept over the psalmist is the wrath against human sin that Christ absorbed, becoming a curse in our place, so that the wrath could be permanently removed from those who trust in him.</p>",
    "17": "<p>\"They surround me like water all day long; they close in on me together.\" The image of hostile forces surrounding \"like water\" — inundating, closing in, inescapable — is the overwhelm of the passion. The crowds surrounding Jesus in the arrest (Luke 22:47-54), the guards surrounding the trial, the crowd surrounding the cross (Luke 23:35) — the closing in that allows no escape. Psalm 22:12-13 (\"many bulls surround me... roaring lions open their mouths against me\") is the companion image. The encirclement Christ experienced at the cross is the full bearing of what the psalmist images in the depths of Sheol.</p>",
    "18": "<p>\"You have put far from me those who love me and my friends; my companions are in darkness.\" The final verse — the psalm ends here, in isolation and darkness, with no resolution. The companions in darkness: in the passion narrative, the disciples flee (Mark 14:50), Peter denies (Matt 26:70-74), and the remaining few \"stood at a distance\" (Luke 23:49). John alone stands at the cross with the women (John 19:25-27). The friends and loved ones in darkness is the Holy Saturday reality — the disciples behind locked doors \"for fear\" (John 20:19). Psalm 88 is the only psalm that ends without resolution; the resolution comes only outside the psalm, in the resurrection that the psalm's darkness makes possible to appreciate.</p>"
  },
  "89": {
    "1": "<p>\"I will sing of the LORD's steadfast love forever; with my mouth I will proclaim your faithfulness to all generations.\" The great Davidic covenant psalm opens with the theme that will both sustain and be tested across 52 verses: the eternal hesed and faithfulness of YHWH as pledged to David. Hebrews 13:8 (\"Jesus Christ is the same yesterday and today and forever\") is the NT statement of the eternal faithfulness. Revelation 1:5 (\"Jesus Christ, who is the faithful witness\") makes Christ the embodiment of the faithfulness proclaimed here. The singing \"to all generations\" anticipates the universal church's song across all ages (Rev 5:9-13).</p>",
    "2": "<p>\"For I declared, 'Your steadfast love is built to stand forever; your faithfulness is established in the heavens themselves.'\" The cosmic establishment of divine faithfulness — permanent as the heavens — is the foundation of the Davidic covenant claim. Hebrews 8:1-2 (Christ as high priest \"who serves in the sanctuary, the true tabernacle set up by the Lord\") and Hebrews 9:24 (Christ entered \"heaven itself, now to appear for us in God's presence\") give the heavenly dimension. The heavenly establishment of faithfulness is now embodied in the exalted Christ at the Father's right hand.</p>",
    "3": "<p>\"'I have made a covenant with my chosen one; I have sworn an oath to David my servant.'\" The Davidic covenant (2 Samuel 7:8-16) in summary. Acts 2:30 (\"God had promised him on oath that he would place one of his descendants on his throne\") and Luke 1:32-33 (\"the Lord God will give him the throne of his father David, and he will reign over Jacob's descendants forever\") are the explicit NT citations of this covenant-oath, fulfilled in Jesus. The \"chosen one\" prefigures the Servant of Isaiah 42:1 (\"my chosen one\") — cited in Matt 12:18 as fulfilled in Christ.</p>",
    "4": "<p>\"'I will make your line endure forever and build your throne for every generation to come.'\" The dual promise: the enduring line (descendants) and the eternal throne. Hebrews 1:5 (\"to which of the angels did God ever say: 'I will be his Father, and he will be my Son'?\" — citing 2 Sam 7:14) establishes that the Davidic son-of-God promise finds its ultimate fulfillment in the eternal Son. Luke 1:32-33 (\"his kingdom will never end\") and Revelation 11:15 (\"he will reign for ever and ever\") are the eschatological fulfillments of the \"every generation\" throne-promise.</p>",
    "5": "<p>\"The heavens praise your wonders, O LORD; your faithfulness is declared in the congregation of the holy ones.\" The praise of the heavens and the declaration among the holy ones — the angelic assembly — are the backdrop for the Davidic covenant claim. Hebrews 1:5-14 extensively contrasts Christ with the angels, establishing that the covenant-Son is superior to the angelic congregation. The \"wonders\" praised by the heavens are, in the NT reading, supremely the incarnation and resurrection (1 Tim 3:16: \"he appeared in the flesh... seen by angels... taken up in glory\" — the heavenly proclamation of the wonder).</p>",
    "6": "<p>\"For who in all the heavens can be compared with the LORD? Who among the heavenly beings is like the LORD?\" The incomparability of YHWH among the heavenly council is what the NT applies to Christ in the exaltation texts. Hebrews 1:4 (\"he became as much superior to the angels as the name he has inherited is superior to theirs\") and Philippians 2:9 (\"the name that is above every name\") ground the incomparability of Christ in the Davidic sonship and the exaltation. No angel, no heavenly being compares to the Son who is seated at the Father's right hand (Heb 1:13: \"sit at my right hand until I make your enemies a footstool\").</p>",
    "7": "<p>\"A God greatly feared in the assembly of the holy ones and awesome above all who surround him.\" The awesome transcendence of YHWH in the divine council is the theological ground for Christ's authority. John 17:5 (\"Father, glorify me in your presence with the glory I had with you before the world began\") refers to the pre-incarnate glory that the Son had in the divine presence — the same assembly of holy ones who surround YHWH in Psalm 89. Revelation 4-5 portrays this assembly gathered around the throne and around the Lamb — the awesome God of the assembly is the God whose throne the Lamb shares.</p>",
    "8": "<p>\"LORD God of hosts, who is as powerful as you, LORD? Your faithfulness wraps around you on every side.\" The divine faithfulness as a surrounding garment — worn on every side — is the consistency of character that grounds the Davidic covenant. 2 Timothy 2:13 (\"if we are faithless, he remains faithful, for he cannot disown himself\") gives the NT equivalent: divine faithfulness is ontological, not behavioral — it cannot be otherwise because it is what God is. The faithfulness that surrounds YHWH on every side is the faithfulness that surrounds Christ's new covenant commitments from every direction.</p>",
    "9": "<p>\"You govern the surging sea; when its waves rear up, you calm them.\" The divine sovereignty over the sea — the chaos-taming power of YHWH — is what the disciples observe in Christ. Mark 4:35-41 (Jesus calming the storm: \"who is this? Even the wind and the waves obey him!\") is the specific miracle that manifests Psalm 89:9's divine power in Christ. The disciples' astonishment (\"who is this?\") is the NT recognition that the one governing the surging sea — the OT marker of YHWH's cosmic sovereignty — is present in Jesus. The stilling of the sea is a Christophany of divine power over chaos.</p>",
    "10": "<p>\"You crushed Rahab like a slaughtered carcass; with your mighty arm you scattered your enemies.\" Rahab here is Egypt and the cosmic chaos-dragon both. The NT reads Christ's death and resurrection as the final crushing of the cosmic enemy: Colossians 2:15 (\"having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross\") and Hebrews 2:14 (\"by his death he might break the power of him who holds the power of death — that is, the devil\"). Revelation 12:9-10 (the great dragon thrown down) is the eschatological form. The mighty arm that scattered divine enemies is the arm of the crucified-and-risen Christ.</p>",
    "11": "<p>\"The heavens belong to you; the earth also is yours; you founded the world and everything in it.\" The divine ownership of creation — heaven and earth — is what Christ claims in the Great Commission. Matthew 28:18 (\"all authority in heaven and on earth has been given to me\") uses the same heaven-and-earth totality. Colossians 1:16-17 (\"all things have been created through him and for him... in him all things hold together\") gives the Christological grounding: Christ is not just given authority over what God owns — he is the one through whom it was made. The founding of the world \"in him\" (John 1:3) means the ownership is already his by creation.</p>",
    "12": "<p>\"North and south — you created them; Tabor and Hermon sing for joy in your name.\" Tabor and Hermon — two prominent mountains of the holy land — sing for joy. The Transfiguration (Matt 17:1-8) is the NT moment where a high mountain literally witnesses the divine presence in Christ: the appearance of Moses and Elijah, the divine voice, and the disciples' prostration all enact what Ps 89:12 images. The mountains sing for joy because the one on the mountain is the divine Son. Creation that declares divine glory finds its focal point at the mount of Transfiguration.</p>",
    "13": "<p>\"Your arm is mighty; your hand is strong; your right hand is raised high.\" The divine arm, hand, and raised right hand — the Exodus imagery of divine power — are what Acts 2:33 applies to Christ: \"exalted to the right hand of God, he has received from the Father the promised Holy Spirit.\" The \"right hand raised high\" is the exaltation position: Hebrews 1:3 (\"after he had provided purification for sins, he sat down at the right hand of the Majesty in heaven\") and Psalm 110:1 (\"sit at my right hand until I make your enemies a footstool\") give the specific form. The mighty arm of the Exodus has become the right hand of the exalted Christ.</p>",
    "14": "<p>\"Righteousness and justice are the foundation of your throne; steadfast love and faithfulness lead the way before you.\" The four moral attributes as throne-foundation and herald-entourage describe the character of divine government that Christ embodies. John 1:14 (\"full of grace and truth\") renders hesed and emet in Greek. Romans 3:25-26 (God presented Christ as the atonement \"to demonstrate his justice... so as to be just and the one who justifies\") shows righteousness and justice worked out through the cross. 2 Corinthians 1:20 (\"all the promises of God find their 'Yes' in him\") is the faithfulness-fulfillment. The throne-foundation attributes of v14 are Christ's character displayed in the gospel.</p>",
    "15": "<p>\"Blessed is the people who know the joyful shout; they walk, LORD, in the light of your face.\" The joyful shout is the battle-cry and worship-cry — the sound of the divine presence advancing. Walking in the light of the divine face is the eschatological blessing of the covenant. John 8:12 (\"I am the light of the world; whoever follows me will never walk in darkness, but will have the light of life\") is Christ's claim to be the light of YHWH's face embodied. Revelation 22:4-5 (\"they will see his face... the Lord God will give them light, and they will reign forever\") is the fulfillment of walking in the light of the divine face.</p>",
    "16": "<p>\"They rejoice in your name all day long and are lifted up by your righteousness.\" The name-rejoicing and righteousness-lifting describe the covenant community's experience of divine favor. Philippians 4:4 (\"rejoice in the Lord always; I will say it again: rejoice!\") is the NT command. Romans 5:2 (\"we boast in the hope of the glory of God\") and Romans 8:30 (\"those he justified he also glorified\") give the righteousness-lifting: those declared righteous in Christ are lifted up to share the divine glory. The all-day rejoicing and the lifting-by-righteousness are both grounded in Christ as the ground of the community's justification.</p>",
    "17": "<p>\"For you are the splendor of their strength; by your favor our strength is raised high.\" Divine splendor as the source of the community's strength — not their own power but the divine glory reflected in them. 2 Corinthians 3:18 (\"we all, who with unveiled faces contemplate the Lord's glory, are being transformed into his image with ever-increasing glory, which comes from the Lord, who is the Spirit\") gives the NT process. Philippians 4:13 (\"I can do all things through him who gives me strength\") is the personal form of the strength-raised-high by divine favor. The splendor is Christ himself, shared with those who are in him.</p>",
    "18": "<p>\"For our shield belongs to the LORD; our king is the Holy One of Israel.\" The king identified as the Holy One of Israel — YHWH's own designation (Isaiah uses it 25 times) — is a significant theological claim: the Davidic king's authority is identified with YHWH the Holy One. Luke 1:35 (\"the holy one to be born will be called the Son of God\") uses the same holiness-language for Jesus. Acts 3:14 (Peter: \"you disowned the Holy and Righteous One\") applies the Holy One title directly to Christ. The Davidic king who is the Holy One of Israel is fulfilled in Jesus, the Son who embodies divine holiness.</p>",
    "19": "<p>\"You spoke in a vision to your faithful servants and said: 'I have given help to a warrior; I have raised up a young man from among the people.'\" The divine oracle raising up the chosen king \"from among the people\" — not from royalty or nobility but from within the community — is the anointing pattern. Acts 2:22 (\"Jesus of Nazareth was a man accredited by God to you by miracles, wonders and signs\") describes Jesus as a man from among the people. Luke 1:26-27 (the annunciation to Mary in Nazareth — an ordinary village) grounds the raising-up-from-among-the-people in the incarnation's obscure and common origin.</p>",
    "20": "<p>\"'I have found David my servant; with my holy oil I have anointed him.'\" The finding and anointing of David is the pattern fulfilled in the anointing of Jesus. Luke 4:18 (\"the Spirit of the Lord is on me, because he has anointed me to proclaim good news to the poor\") cites Isaiah 61:1 as the fulfillment — Christ's anointing by the Spirit at baptism (Luke 3:22) is the \"holy oil\" anointing of Psalm 89:20. Acts 10:38 (\"God anointed Jesus of Nazareth with the Holy Spirit and power\") is the explicit NT statement. The name \"Christ\" (<em>Christos</em> = Anointed One) encodes this anointing as Jesus's defining identity.</p>",
    "21": "<p>\"'My hand will uphold him steadily; my arm will give him strength.'\" The divine upholding of the anointed king — the hand that does not let go — is the Father's sustaining of the Son throughout the incarnate ministry. Isaiah 42:1 (\"here is my servant, whom I uphold\") is the Servant parallel. John 10:28-29 (\"no one can snatch them out of my hand... no one can snatch them out of my Father's hand\") is the double-upholding: the Son upholds those given to him, and the Father upholds both. Hebrews 13:5 (\"never will I leave you; never will I forsake you\") is the covenant promise of the steady upholding to all who are in Christ.</p>",
    "22": "<p>\"'No enemy will overpower him; no wicked person will oppress him.'\" The divine protection of the anointed king from enemy and oppressor — a promise that appears refuted by the passion but is vindicated by the resurrection. John 16:33 (\"I have overcome the world\") is Christ's claim to have fulfilled v22 — not by escaping suffering but by overcoming it through the resurrection. Colossians 2:15 (the public triumph over the powers) is the resurrection-defeat of all who \"overpowered\" him at the cross. The apparent defeat is the hidden victory; no enemy ultimately prevails against the one the Father upholds.</p>",
    "23": "<p>\"'I will shatter his enemies before his eyes and defeat all who hate him.'\" The divine defeat of the enemies of the anointed king — accomplished through the resurrection and anticipated in the final judgment. 1 Corinthians 15:25 (\"for he must reign until he has put all his enemies under his feet\") is the NT timeline: the shattering is progressive, from resurrection through the age, until the final defeat of the last enemy (death itself, 1 Cor 15:26). Revelation 19:11-16 (the rider on the white horse who \"judges and wages war\") is the eschatological fulfillment of the shattering.</p>",
    "24": "<p>\"'My faithfulness and steadfast love will be with him; through my name his strength will be raised high.'\" The hesed and faithfulness as the anointed king's constant companions is what Christ's mediation provides to the church. John 17:11-12 (\"Holy Father, protect them by the power of your name... I protected them and kept them safe\") shows Christ as the one who walked in and distributed the Father's name-and-faithfulness protection. In the new covenant, what YHWH's faithfulness was to David is what Christ's mediation is to the church: the same divine steadfast love channeled through the anointed heir.</p>",
    "25": "<p>\"'I will extend his dominion to the sea and his right hand over the rivers.'\" The universal dominion — sea to sea, rivers — is the imperial scope of the Davidic king's reign fulfilled in Christ's Great Commission and global lordship. Matthew 28:18-19 (\"all authority in heaven and on earth has been given to me; go therefore and make disciples of all nations\") is the dominion-to-the-sea mission extended to all geography. Revelation 11:15 (\"the kingdom of the world has become the kingdom of our Lord and of his Messiah\") is the eschatological fulfillment. Psalm 72:8 (\"he will rule from sea to sea\") is the companion messianic text.</p>",
    "26": "<p>\"'He will call out to me, \"You are my Father, my God, and the Rock who saves me!\"'\" The Davidic king's cry to YHWH as \"my Father\" — the filial address — is what the NT elevates to the unique Sonship of Christ. Hebrews 1:5 cites 2 Samuel 7:14 (\"I will be his Father, and he will be my Son\") as fulfilled in Christ and asks: \"to which of the angels did God ever say\" this? The answer: only to the Son. Romans 8:15 (\"by him we cry, 'Abba, Father'\" — the Aramaic form of the Father-address) gives believers participation in this filial cry through the Spirit of adoption.</p>",
    "27": "<p>\"'I will appoint him as my firstborn, the highest of all the kings of the earth.'\" A direct citation: Revelation 1:5 (\"Jesus Christ, who is the faithful witness, the firstborn from the dead, and the ruler of the kings of the earth\") cites this verse directly, applying both \"firstborn\" and \"ruler of the kings of the earth\" to the risen Christ. Colossians 1:15 (\"the firstborn over all creation\") and Colossians 1:18 (\"the firstborn from among the dead\") give the two dimensions of the firstborn status: first in creation's order and first in the resurrection order. The highest-of-all-kings is the fulfillment of the Davidic promise in the exalted Christ enthroned above every earthly authority.</p>",
    "28": "<p>\"'I will maintain my steadfast love for him forever, and my covenant with him will be secure.'\" The eternal maintenance of divine hesed toward the anointed heir is what Hebrews 7:22 attributes to Christ: \"Jesus has become the guarantor of a better covenant.\" The covenant with him is secure not because of Christ's human faithfulness but because of the divine oath sworn to him (Heb 7:20-21; citing Ps 110:4). Hebrews 13:20 (\"the God of peace, who through the blood of the eternal covenant brought back from the dead our Lord Jesus\") names the covenant explicitly as the ground of the resurrection.</p>",
    "29": "<p>\"'His line will continue forever, and his throne will last as long as the heavens above.'\" The \"line forever\" and \"throne as long as the heavens\" find their fulfillment in the eternal Sonship. Luke 1:32-33 (\"the Lord God will give him the throne of his father David... his kingdom will never end\") is the angelic declaration of this promise's fulfillment. Hebrews 1:8 (\"your throne, O God, will last forever and ever\") — citing Ps 45:6 — attributes an eternal throne directly to the Son. The heavens-enduring throne of the Davidic promise is Christ's permanent reign.</p>",
    "30": "<p>\"'If his descendants abandon my instruction and refuse to live by my rulings,'\" The conditional clause that begins in v30 and runs through v32 is the theological key to why every historical Davidic king failed. Solomon abandoned YHWH's instruction (1 Kings 11:1-13); the subsequent kings broke the decrees. The \"if\" clauses show that the Davidic covenant required a Davidic heir who would keep the covenant perfectly — and every human heir failed. Christ alone is the Davidic descendant who never abandoned the divine instruction, who lived by all the rulings, and is therefore the one in whom the unconditional promises of vv33-37 can be fulfilled without the conditional penalties of vv30-32.</p>",
    "31": "<p>\"'if they break my decrees and fail to keep my commandments,'\" The second conditional: breaking of decrees and failure to keep commandments. Romans 3:23 (\"all have sinned and fall short of the glory of God\") describes the universal fulfillment of this condition — all Davidic heirs broke the decrees. But Romans 5:19 (\"through the obedience of the one man the many will be made righteous\") names the exception: Christ's obedience to the commandments is complete and covers the covenant-breaking of all the sons before him. The condition of v31 is met in every human Davidic king; the unconditional promise of v33 is met only in Christ, whose obedience is total.</p>",
    "32": "<p>\"'then I will punish their rebellion with a rod and their sin with blows.'\" The punitive consequence — the rod and blows for the failing Davidic heir — is what the prophets describe in the exile: YHWH's punishment of Israel's unfaithful kings through Assyria and Babylon. Isaiah 53:5 (\"the punishment that brought us peace was on him\") is the NT reappropriation: the blows and rod that the failing heirs deserved fell on the faithful Son. The punishment for the son's covenant-breaking is borne by the one who kept the covenant perfectly — substitutionary punishment for the failures of the whole Davidic line and of all humanity.</p>",
    "33": "<p>\"'But I will not withdraw my steadfast love from him or betray my faithfulness.'\" The unconditional element that follows the conditional penalties: even if the descendants fail and are punished, the hesed toward the covenant line will not be withdrawn. This is the theological ground for the incarnation: YHWH's hesed toward the Davidic line is what sends the Son even when the human Davidic dynasty has collapsed. Romans 5:8 (\"God demonstrates his own love for us in this: while we were still sinners, Christ died for us\") is the ultimate demonstration that YHWH never withdrew hesed even in the face of total human covenant failure.</p>",
    "34": "<p>\"'I will not break my covenant or change what I have spoken.'\" The inviolability of the divine covenant-word. Numbers 23:19 (\"God is not human, that he should lie... does he speak and then not act? Does he promise and not fulfill?\") is the ground. 2 Corinthians 1:20 (\"all the promises of God find their 'Yes' in him\") is the NT claim that every covenant-word, including the Davidic covenant, finds its inviolable fulfillment in Christ. The covenant is not broken by the apparent failure of the Davidic line or by the cross; rather, the cross is the mechanism by which the covenant is kept — the \"Yes\" enacted in the most unlikely way.</p>",
    "35": "<p>\"'I have sworn by my own holiness once and for all; I will not deceive David.'\" The divine oath sworn by YHWH's own holiness — the highest possible oath — is what Hebrews 6:17-18 explicates: \"because God wanted to make the unchanging nature of his purpose very clear to the heirs of what was promised, he confirmed it with an oath... we who have fled to take hold of the hope set before us may be greatly encouraged.\" The sworn-by-holiness oath to David is the unbreakable ground of the covenant, and Christ is the one in whom its fulfillment is certain.</p>",
    "36": "<p>\"'His descendants will endure forever; his throne will last as long as the sun shines before me.'\" The sun-permanence of the Davidic throne finds its fulfillment in Christ's eternal reign. Revelation 22:5 (\"there will be no more night... and they will reign forever and ever\") ironically reverses the sun-image: in the new creation, there is no need of the sun because the Lamb is the light — the throne endures beyond the sun itself. Hebrews 1:11-12 (the heavens \"will perish\" but Christ \"remains\") establishes that Christ's permanence exceeds the permanence of the creation by which the covenant is illustrated.</p>",
    "37": "<p>\"'Like the moon it will be established forever, that faithful witness set in the heavens.'\" The moon as faithful witness — its monthly cycle reliable and unceasing — is transferred to the Davidic covenant. Revelation 1:5 (\"Jesus Christ, who is the faithful witness\") applies both the David-promise (v27: firstborn, highest of kings) and the witness-language to Christ. The \"faithful witness\" set in the heavens is Christ, now permanently established at the Father's right hand, whose witness to the Father and to the world is as reliable as the moon's cycle — and more so, since the heavens pass away but the Son's witness does not (Matt 24:35).</p>",
    "38": "<p>\"But now you have cast off and rejected him; you are enraged against your anointed king.\" The pivot — the most brutal turn in the Psalms. After 37 verses of covenant confidence, the psalm confronts the apparent divine rejection of the Davidic anointed. This verse and what follows (vv38-51) are the theological problem that the NT answers with the resurrection. Mark 8:31 (\"the Son of Man must... be rejected by the elders, the chief priests and the teachers of the law\") and Luke 17:25 (\"he must suffer many things and be rejected\") use the same rejection-language. The \"casting off\" and divine rage toward the anointed is what the cross looks like before Easter.</p>",
    "39": "<p>\"You have repudiated the covenant with your servant; you have thrown his crown into the dust.\" The crown thrown into the dust is the passion-image: at the crucifixion, the crown placed on Jesus's head is a crown of thorns (Matt 27:29) — the mockery of kingship, the literal throwing of royal dignity into the dirt. The apparent repudiation of the covenant is what the disciples experienced between Friday and Sunday. John 20:19 (\"the doors were locked for fear of the Jewish leaders\") shows the disciples living in the reality of this verse: the covenant appeared repudiated, the crown in the dust.</p>",
    "40": "<p>\"You have broken down all his walls and reduced his fortifications to rubble.\" The defensive structures of the anointed king broken down — the exposure and vulnerability of the one who should be protected. At the cross: the legal protections fail (Pilate knows he is innocent but condemns him; Luke 23:22-25), the social protections fail (the disciples flee), the divine protection appears withdrawn (the cry of dereliction). The walls broken down and fortifications reduced to rubble are the stripped-away protections that leave Christ exposed on the cross — the precise condition required for the substitutionary death that could not be accomplished behind walls.</p>",
    "41": "<p>\"All who pass by strip him of what he has; he has become a mockery to his neighbors.\" The stripping and mocking — the passion-narrative language. Matthew 27:27-31 (the soldiers strip Jesus of his clothes and mock him) and Matthew 27:35 (\"they divided up his clothes by casting lots\") are the literal fulfillments. Luke 23:35-39 (\"the rulers even sneered at him... the soldiers also came up and mocked him\") gives the social dimension. Lamentations 1:12 (\"Is it nothing to you, all you who pass by?\") uses the same \"all who pass by\" language for Jerusalem's suffering — both the psalmist's image and the lament express the same devastation.</p>",
    "42": "<p>\"You have strengthened the hand of his enemies; you have let all who hate him celebrate.\" The apparent divine assistance to the enemies of the anointed — the most theologically difficult claim in this section. Luke 22:53 (\"but this is your hour — when darkness reigns\") is Christ's own recognition that the power of the enemies has been given its moment. Acts 2:23 (\"this man was handed over to you by God's deliberate plan and foreknowledge; and you, with the help of wicked men, put him to death\") gives the paradox its NT resolution: the enemies are \"strengthened\" by divine permission as part of the saving plan. The celebration of those who hate him is the Friday celebration that Sunday overturns.</p>",
    "43": "<p>\"You have blunted his sword in battle and failed to hold him up when he fought.\" The failure of the anointed king's weapons and the divine non-upholding in battle. At Gethsemane, Christ says \"put your sword away\" (John 18:11) — the literal blunting of the weapon. In the trial, the theological defense is met with silence: Matthew 27:14 (\"he gave no answer, not even to a single charge — to the great amazement of the governor\"). The non-upholding is the withdrawal of the divine intervention that could have prevented the cross — the Father \"failed to hold him up\" not through abandonment but through the purposive allowing of the death (Acts 2:23).</p>",
    "44": "<p>\"You have stripped away his glory and hurled his throne down to the ground.\" The glory stripped away — the kenosis of Philippians 2:7 (\"he emptied himself, taking the form of a servant\") — and the throne hurled down are the incarnation and the cross together. The Transfiguration briefly showed the glory beneath the humiliation (Matt 17:2); the cross is the moment when the glory appears entirely gone, the throne apparently destroyed. Hebrews 12:2 (\"for the joy set before him he endured the cross, scorning its shame\") identifies the cross as the place of the scorned throne — the kingship exercised in the most shameful possible form, only to be revealed as the path to the eternal throne (Heb 1:8).</p>",
    "45": "<p>\"You have shortened the days of his prime and wrapped him in shame.\" The cut-short days and shame-wrapping are the passion-language of humiliation and premature death. Hebrews 12:2 (\"scorning its shame\") and Philippians 2:8 (\"death on a cross\" — the shameful execution reserved for criminals and enemies of Rome) give the NT form. Jesus dies at approximately thirty-three years old, at the height of a human life. Yet Revelation 1:17-18 (\"I am the Living One; I was dead, and now look, I am alive forever and ever\") reverses the shortening: the risen Christ has not shortened days but endless days — the apparent cutting-short is the beginning of the endless.</p>",
    "46": "<p>\"How long, O LORD? Will you hide yourself away forever? How long will your anger blaze like fire?\" The how-long cry — the lament question about divine hiddenness — is the cry of the interval between the cross and the second coming. The disciples lived this question in the three days between crucifixion and resurrection. The church lives it in the age between Pentecost and parousia. Revelation 6:10 (\"how long, Sovereign Lord, holy and true, until you judge the inhabitants of the earth and avenge our blood?\") is the eschatological form. The fire-like anger that blazes is the wrath absorbed by Christ at the cross, whose \"how long\" is answered by the resurrection's declaration that it is finished.</p>",
    "47": "<p>\"Remember how short my span of life is! For what emptiness you have made all the children of man!\" The brevity of human life and the vanity that death exposes — the existential crisis that underlies the covenant lament. Hebrews 2:14-15 (\"since the children have flesh and blood, he too shared in their humanity so that by his death he might break the power of him who holds the power of death — that is, the devil — and free those who all their lives were held in slavery by their fear of death\") gives the specific reason Christ takes on the short span: to break the death-power from within human mortality. The emptiness made of all the children of man is precisely what the resurrection overcomes.</p>",
    "48": "<p>\"What man can go on living and never see death? Who can rescue his life from the grip of the grave?\" The rhetorical questions that expect \"no one\" — the universal mortality of every human. But Christ is the exception who makes the questions answerable. John 11:26 (\"whoever lives by believing in me will never die — do you believe this?\") and 1 Corinthians 15:54-55 (\"death has been swallowed up in victory. 'Where, O death, is your victory? Where, O death, is your sting?'\") are the NT answers. Christ rescues his life from the grip of the grave (Acts 2:24: \"it was impossible for death to keep its hold on him\") and thereby makes possible the rescue of all who are in him.</p>",
    "49": "<p>\"Lord, where is your steadfast love of old, which in your faithfulness you swore to David?\" The covenant question — the lament that the sworn promise appears unfulfilled. This is the cry that resurrection answers definitively. Acts 13:32-34 (Paul in Antioch: \"we tell you the good news: what God promised our ancestors he has fulfilled for us, their children, by raising up Jesus... 'I will give you the holy and sure blessings promised to David'\") is the explicit citation of the Davidic promise as fulfilled in the resurrection. The \"where is your hesed\" of v49 receives the answer: it is in the resurrection of Jesus, the fulfillment of what was sworn to David.</p>",
    "50": "<p>\"Remember, Lord, the mocking your servants endure — how I bear in my heart the taunts of all those nations.\" The internalized mockery — the taunts of the nations carried in the heart of the suffering servant — is the burden of shame borne by Christ and shared with his disciples. Hebrews 11:26 (Moses \"regarded disgrace for the sake of Christ as of greater value than the treasures of Egypt\") and Hebrews 13:13 (\"let us go to him outside the camp, bearing the disgrace he bore\") make the bearing of mockery a participation in Christ's own experience. The taunts of the nations that the psalmist carries in his heart are the taunts that Christ carried through the passion and that his witnesses bear after him.</p>",
    "51": "<p>\"with which your enemies, LORD, have taunted, mocking every step of your anointed king.\" The mocking of every step of the anointed's journey — the sustained ridicule of the Messianic claim. Luke 23:35-39 describes successive layers of mocking at the cross: the rulers sneered, the soldiers mocked, even one of the crucified criminals hurled insults. The mocking of \"every step\" — from entry into Jerusalem through the trials and crucifixion — is the sustained taunt that the anointed king endures. John 19:14-15 (Pilate: \"here is your king!\"; crowd: \"take him away! Crucify him!\") is the specific mocking of the kingship claim at its climax.</p>",
    "52": "<p>\"Blessed be the LORD forever! Amen and Amen.\" The doxology that closes Book III of the Psalter — not a conclusion to the lament of Psalm 89 but an editorial seam marking the end of the third book. Yet placed here, after the profound lament of the Davidic covenant's apparent collapse, this doxology has the quality of faith that persists beyond what can be seen. Hebrews 11:1 (\"faith is confidence in what we hope for and assurance about what we do not see\") describes exactly this: blessing YHWH in the face of the covenant's apparent failure. The resurrection is the answer that vindicates the doxology: Revelation 5:13 (\"to him who sits on the throne and to the Lamb be praise and honor and glory and power, for ever and ever\") is the eschatological Amen and Amen.</p>"
  }
}

def main():
    data = load_comm('mkt-christ', 'psalms')
    merge_comm(data, PSALMS)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Psalms christ: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-christ', 'psalms', data)

if __name__ == '__main__':
    main()
